const M = 'http://genai-mlflow.genai.svc.cluster.local/api/2.0/mlflow';
const body = $input.item.json.body;
const action = body.action;
var MAX_MESSAGES = Number($env.SESSION_MAX_MESSAGES || 50);

try {

if (!action) throw new Error('action required: create, get, append, list, close');

async function post(path, data) {
  var r = await fetch(M + path, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function apiGet(path) {
  var r = await fetch(M + path);
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function getOrCreateExperiment(name) {
  try {
    var res = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(name));
    return res.experiment.experiment_id;
  } catch(e) {
    var cr = await post('/experiments/create', {name: name});
    return cr.experiment_id;
  }
}

async function findRunByTag(expId, tagKey, tagValue) {
  var filter = "tags.`" + tagKey + "` = '" + tagValue.replace(/'/g, "\\'") + "'";
  var res = await post('/runs/search', {
    experiment_ids: [expId],
    filter: filter,
    max_results: 1
  });
  return (res.runs && res.runs.length > 0) ? res.runs[0] : null;
}

// ── CREATE ────────────────────────────────────────────────────────────────
if (action === 'create') {
  var sessionId = body.session_id || ('sess_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6));
  var expId = await getOrCreateExperiment('__sessions');
  var ts = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: ts,
    run_name: sessionId
  });
  var runId = runRes.run.info.run_id;
  var tags = [
    {key: 'session_id', value: sessionId},
    {key: 'status', value: 'active'}
  ];
  var params = [
    {key: 'session_id', value: sessionId}
  ];
  if (body.metadata) {
    tags.push({key: 'metadata', value: JSON.stringify(body.metadata).substring(0, 5000)});
  }
  await post('/runs/log-batch', {
    run_id: runId,
    params: params,
    metrics: [{key: 'message_count', value: 0, timestamp: ts, step: 0}],
    tags: tags
  });
  return {action: 'create', session_id: sessionId, run_id: runId, status: 'active'};
}

// ── GET ───────────────────────────────────────────────────────────────────
if (action === 'get') {
  var sessionId = body.session_id;
  if (!sessionId) throw new Error('session_id required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__sessions'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No sessions found');
  }
  var run = await findRunByTag(expId, 'session_id', sessionId);
  if (!run) return {action: 'get', session_id: sessionId, messages: [], message_count: 0, session_exists: false, status: 'not_found'};
  var info = run.info || {};
  var tags = {};
  (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
  var metrics = {};
  (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
  // Reconstruct messages from indexed tags
  var msgCount = Number(metrics.message_count || 0);
  var messages = [];
  for (var i = 0; i < msgCount; i++) {
    var role = tags['msg_' + i + '_role'] || '';
    var content = tags['msg_' + i + '_content'] || '';
    if (role) messages.push({role: role, content: content});
  }
  return {
    action: 'get',
    session_id: sessionId,
    run_id: info.run_id,
    status: tags.status || (info.status === 'FINISHED' ? 'closed' : 'active'),
    message_count: msgCount,
    messages: messages,
    session_full: msgCount >= MAX_MESSAGES,
    max_messages: MAX_MESSAGES,
    created_at: Number(info.start_time)
  };
}

// ── APPEND ────────────────────────────────────────────────────────────────
if (action === 'append') {
  var sessionId = body.session_id;
  var role = body.role;
  var content = body.content;
  if (!sessionId) throw new Error('session_id required');
  if (!role || !content) throw new Error('role and content required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__sessions'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No sessions found');
  }
  var run = await findRunByTag(expId, 'session_id', sessionId);
  if (!run) {
    // Auto-create session if not found (first message race condition)
    var ts2 = Date.now();
    var runRes2 = await post('/runs/create', {experiment_id: expId, start_time: ts2, run_name: sessionId});
    var runId2 = runRes2.run.info.run_id;
    await post('/runs/log-batch', {run_id: runId2, params: [{key:'session_id',value:sessionId}], metrics:[{key:'message_count',value:0,timestamp:ts2,step:0}], tags:[{key:'session_id',value:sessionId},{key:'status',value:'active'}]});
    run = {info: {run_id: runId2}, data: {tags: [], metrics: []}};
  }
  var runId = run.info.run_id;
  var metrics = {};
  (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
  var msgIdx = Number(metrics.message_count || 0);
  if (msgIdx >= MAX_MESSAGES) {
    return {action: 'append', session_id: sessionId, run_id: runId, message_count: msgIdx, session_full: true, max_messages: MAX_MESSAGES, _status: 409};
  }
  var ts = Date.now();
  await post('/runs/log-batch', {
    run_id: runId,
    tags: [
      {key: 'msg_' + msgIdx + '_role', value: role},
      {key: 'msg_' + msgIdx + '_content', value: String(content).substring(0, 5000)}
    ],
    metrics: [{key: 'message_count', value: msgIdx + 1, timestamp: ts, step: msgIdx + 1}]
  });
  return {action: 'append', session_id: sessionId, run_id: runId, message_index: msgIdx, message_count: msgIdx + 1, session_full: (msgIdx + 1) >= MAX_MESSAGES, max_messages: MAX_MESSAGES};
}

// ── LIST ──────────────────────────────────────────────────────────────────
if (action === 'list') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__sessions'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'list', sessions: [], count: 0};
  }
  var filters = [];
  if (body.status === 'active') filters.push("tags.`status` = 'active'");
  var searchBody = {
    experiment_ids: [expId],
    max_results: body.limit || 25,
    order_by: ['start_time DESC']
  };
  if (filters.length > 0) searchBody.filter = filters.join(' AND ');
  var searchRes = await post('/runs/search', searchBody);
  var sessions = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var tags = {};
    (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      session_id: tags.session_id || info.run_name || '',
      run_id: info.run_id,
      status: tags.status || (info.status === 'FINISHED' ? 'closed' : 'active'),
      message_count: Number(metrics.message_count || 0),
      created_at: Number(info.start_time)
    };
  });
  return {action: 'list', sessions: sessions, count: sessions.length};
}

// ── CLOSE ─────────────────────────────────────────────────────────────────
if (action === 'close') {
  var sessionId = body.session_id;
  if (!sessionId) throw new Error('session_id required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__sessions'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No sessions found');
  }
  var run = await findRunByTag(expId, 'session_id', sessionId);
  if (!run) {
    // Auto-create session if not found (first message race condition)
    var ts2 = Date.now();
    var runRes2 = await post('/runs/create', {experiment_id: expId, start_time: ts2, run_name: sessionId});
    var runId2 = runRes2.run.info.run_id;
    await post('/runs/log-batch', {run_id: runId2, params: [{key:'session_id',value:sessionId}], metrics:[{key:'message_count',value:0,timestamp:ts2,step:0}], tags:[{key:'session_id',value:sessionId},{key:'status',value:'active'}]});
    run = {info: {run_id: runId2}, data: {tags: [], metrics: []}};
  }
  var runId = run.info.run_id;
  await post('/runs/set-tag', {run_id: runId, key: 'status', value: 'closed'});
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
  return {action: 'close', session_id: sessionId, run_id: runId, status: 'closed'};
}

throw new Error('Unknown action: ' + action);

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, action: action || 'unknown', _status: status};
}
